module RefModule (
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    input [1:0] sel,
    output reg [7:0] y
);

    // Multiplexer logic
    always @(*) begin
        case (sel)
            2'b00: y = a;
            2'b01: y = b;
            2'b10: y = c;
            2'b11: y = d;
            default: y = 8'b0;
        endcase
    end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
